// ==================== Input Sanitizer ====================

package com.ecommerce.search.util;

import java.util.regex.Pattern;

public final class InputSanitizer {

    private static final Pattern SCRIPT_PATTERN = Pattern.compile("<script[^>]*>.*?</script>", Pattern.CASE_INSENSITIVE | Pattern.DOTALL);
    private static final Pattern HTML_TAG_PATTERN = Pattern.compile("<[^>]+>");
    private static final Pattern ES_SPECIAL_CHARS = Pattern.compile("[+\\-=&|><!(){}\\[\\]^\"~*?:\\\\/]");

    private InputSanitizer() {}

    public static String sanitizeHtml(String input) {
        if (input == null) return null;
        String sanitized = SCRIPT_PATTERN.matcher(input).replaceAll("");
        sanitized = HTML_TAG_PATTERN.matcher(sanitized).replaceAll("");
        return sanitized.trim();
    }

    public static String sanitizeSearchQuery(String input) {
        if (input == null) return null;
        String sanitized = sanitizeHtml(input);
        sanitized = ES_SPECIAL_CHARS.matcher(sanitized).replaceAll(" ");
        sanitized = sanitized.replaceAll("\\s+", " ").trim();
        if (sanitized.length() > 500) {
            sanitized = sanitized.substring(0, 500);
        }
        return sanitized;
    }

    public static String sanitizeFieldValue(String input) {
        if (input == null) return null;
        return sanitizeHtml(input).trim();
    }
}

