package com.ecommerce.search.service;

import com.ecommerce.search.dto.SearchRequest;
import com.ecommerce.search.dto.SearchResponse;
import com.ecommerce.search.dto.SearchResponse.FacetEntry;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.model.SearchQuery;
import com.ecommerce.search.util.InputSanitizer;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.elasticsearch.action.bulk.BulkRequest;
import org.elasticsearch.action.bulk.BulkResponse;
import org.elasticsearch.action.delete.DeleteRequest;
import org.elasticsearch.action.delete.DeleteResponse;
import org.elasticsearch.action.get.GetRequest;
import org.elasticsearch.action.get.GetResponse;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequestBuilder;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.action.update.UpdateResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.histogram.Histogram;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortBuilders;
import org.elasticsearch.search.sort.SortOrder;
import org.elasticsearch.search.suggest.SuggestBuilder;
import org.elasticsearch.search.suggest.SuggestBuilders;
import org.elasticsearch.search.suggest.completion.CompletionSuggestion;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductService {

    private static final Logger logger = LoggerFactory.getLogger(ProductService.class);

    @Autowired
    private RestHighLevelClient client;

    @Autowired
    private SearchQueryService searchQueryService;

    private final ObjectMapper objectMapper;

    public ProductService() {
        this.objectMapper = new ObjectMapper();
        this.objectMapper.registerModule(new JavaTimeModule());
    }

    public Product indexProduct(Product product) throws IOException {
        product.setName(InputSanitizer.sanitizeFieldValue(product.getName()));
        product.setDescription(InputSanitizer.sanitizeFieldValue(product.getDescription()));
        product.setCategory(InputSanitizer.sanitizeFieldValue(product.getCategory()));
        product.setBrand(InputSanitizer.sanitizeFieldValue(product.getBrand()));

        if (product.getId() == null || product.getId().isEmpty()) {
            product.setId(UUID.randomUUID().toString());
        }
        product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());

        String jsonString = objectMapper.writeValueAsString(product);

        IndexRequest request = new IndexRequest(IndexManagementService.PRODUCTS_INDEX)
                .id(product.getId())
                .source(jsonString, XContentType.JSON);

        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        logger.info("Product indexed: id={}, result={}", product.getId(), response.getResult().name());

        return product;
    }

    public BulkResponse bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();

        for (Product product : products) {
            product.setName(InputSanitizer.sanitizeFieldValue(product.getName()));
            product.setDescription(InputSanitizer.sanitizeFieldValue(product.getDescription()));
            product.setCategory(InputSanitizer.sanitizeFieldValue(product.getCategory()));
            product.setBrand(InputSanitizer.sanitizeFieldValue(product.getBrand()));

            if (product.getId() == null || product.getId().isEmpty()) {
                product.setId(UUID.randomUUID().toString());
            }
            product.setCreatedAt(Instant.now());
            product.setUpdatedAt(Instant.now());

            String jsonString = objectMapper.writeValueAsString(product);

            IndexRequest request = new IndexRequest(IndexManagementService.PRODUCTS_INDEX)
                    .id(product.getId())
                    .source(jsonString, XContentType.JSON);

            bulkRequest.add(request);
        }

        BulkResponse bulkResponse = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        logger.info("Bulk indexed {} products, hasFailures={}", products.size(), bulkResponse.hasFailures());

        if (bulkResponse.hasFailures()) {
            logger.warn("Bulk index failures: {}", bulkResponse.buildFailureMessage());
        }

        return bulkResponse;
    }

    public Product getProduct(String id) throws IOException {
        if (id == null || id.isEmpty()) {
            throw new IllegalArgumentException("Product ID cannot be null or empty");
        }

        GetRequest request = new GetRequest(IndexManagementService.PRODUCTS_INDEX, id);
        GetResponse response = client.get(request, RequestOptions.DEFAULT);

        if (!response.isExists()) {
            return null;
        }

        Product product = objectMapper.readValue(response.getSourceAsString(), Product.class);
        product.setId(response.getId());
        return product;
    }

    public Product updateProduct(String id, Product product) throws IOException {
        if (id == null || id.isEmpty()) {
            throw new IllegalArgumentException("Product ID cannot be null or empty");
        }

        product.setName(InputSanitizer.sanitizeFieldValue(product.getName()));
        product.setDescription(InputSanitizer.sanitizeFieldValue(product.getDescription()));
        product.setCategory(InputSanitizer.sanitizeFieldValue(product.getCategory()));
        product.setBrand(InputSanitizer.sanitizeFieldValue(product.getBrand()));
        product.setUpdatedAt(Instant.now());
        product.setId(id);

        String jsonString = objectMapper.writeValueAsString(product);

        UpdateRequest request = new UpdateRequest(IndexManagementService.PRODUCTS_INDEX, id)
                .doc(jsonString, XContentType.JSON)
                .docAsUpsert(false);

        UpdateResponse response = client.update(request, RequestOptions.DEFAULT);
        logger.info("Product updated: id={}, result={}", id, response.getResult().name());

        return product;
    }

    public boolean deleteProduct(String id) throws IOException {
        if (id == null || id.isEmpty()) {
            throw new IllegalArgumentException("Product ID cannot be null or empty");
        }

        DeleteRequest request = new DeleteRequest(IndexManagementService.PRODUCTS_INDEX, id);
        DeleteResponse response = client.delete(request, RequestOptions.DEFAULT);

        logger.info("Product deleted: id={}, result={}", id, response.getResult().name());
        return response.getResult() == org.elasticsearch.action.DocWriteResponse.Result.DELETED;
    }

    public SearchResponse search(SearchRequest searchRequest, String userId, String sessionId) throws IOException {
        long startTime = System.currentTimeMillis();

        String sanitizedQuery = InputSanitizer.sanitizeSearchQuery(searchRequest.getQuery());

        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCTS_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        // Always filter for active products
        boolQuery.filter(QueryBuilders.termQuery("active", true));

        // Full-text search
        if (sanitizedQuery != null && !sanitizedQuery.isEmpty()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(sanitizedQuery, "name^3", "description^1", "brand^2", "tags^1.5")
                    .fuzziness("AUTO")
                    .minimumShouldMatch("75%"));
        }

        // Category filter
        if (searchRequest.getCategory() != null && !searchRequest.getCategory().isEmpty()) {
            String sanitizedCategory = InputSanitizer.sanitizeFieldValue(searchRequest.getCategory());
            boolQuery.filter(QueryBuilders.termQuery("category", sanitizedCategory));
        }

        // Brand filter
        if (searchRequest.getBrand() != null && !searchRequest.getBrand().isEmpty()) {
            String sanitizedBrand = InputSanitizer.sanitizeFieldValue(searchRequest.getBrand());
            boolQuery.filter(QueryBuilders.termQuery("brand", sanitizedBrand));
        }

        // Price range filter
        if (searchRequest.getMinPrice() != null || searchRequest.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (searchRequest.getMinPrice() != null) {
                rangeQuery.gte(searchRequest.getMinPrice().doubleValue());
            }
            if (searchRequest.getMaxPrice() != null) {
                rangeQuery.lte(searchRequest.getMaxPrice().doubleValue());
            }
            boolQuery.filter(rangeQuery);
        }

        // Rating filter
        if (searchRequest.getMinRating() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("rating").gte(searchRequest.getMinRating()));
        }

        // Tags filter
        if (searchRequest.getTags() != null && !searchRequest.getTags().isEmpty()) {
            List<String> sanitizedTags = searchRequest.getTags().stream()
                    .map(InputSanitizer::sanitizeFieldValue)
                    .filter(t -> t != null && !t.isEmpty())
                    .collect(Collectors.toList());
            if (!sanitizedTags.isEmpty()) {
                boolQuery.filter(QueryBuilders.termsQuery("tags", sanitizedTags));
            }
        }

        // In stock filter
        if (searchRequest.getInStock() != null && searchRequest.getInStock()) {
            boolQuery.filter(QueryBuilders.rangeQuery("stockQuantity").gt(0));
        }

        sourceBuilder.query(boolQuery);

        // Sorting
        applySorting(sourceBuilder, searchRequest.getSortBy());

        // Pagination
        int from = searchRequest.getPage() * searchRequest.getPageSize();
        sourceBuilder.from(from);
        sourceBuilder.size(searchRequest.getPageSize());

        // Faceted aggregations
        sourceBuilder.aggregation(AggregationBuilders.terms("categories")
                .field("category").size(50));
        sourceBuilder.aggregation(AggregationBuilders.terms("brands")
                .field("brand").size(50));
        sourceBuilder.aggregation(AggregationBuilders.terms("tags_agg")
                .field("tags").size(50));
        sourceBuilder.aggregation(AggregationBuilders.histogram("price_ranges")
                .field("price").interval(50).minDocCount(1));
        sourceBuilder.aggregation(AggregationBuilders.histogram("rating_ranges")
                .field("rating").interval(1).minDocCount(1));

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
                client.search(esRequest, RequestOptions.DEFAULT);

        long responseTime = System.currentTimeMillis() - startTime;

        // Build response
        SearchResponse response = new SearchResponse();
        List<Product> products = new ArrayList<>();

        for (SearchHit hit : esResponse.getHits().getHits()) {
            Product product = objectMapper.readValue(hit.getSourceAsString(), Product.class);
            product.setId(hit.getId());
            products.add(product);
        }

        response.setProducts(products);
        response.setTotalHits(esResponse.getHits().getTotalHits().value);
        response.setPage(searchRequest.getPage());
        response.setPageSize(searchRequest.getPageSize());
        response.setTotalPages((int) Math.ceil((double) response.getTotalHits() / searchRequest.getPageSize()));
        response.setResponseTimeMs(responseTime);

        // Parse facets
        Map<String, List<FacetEntry>> facets = new LinkedHashMap<>();

        if (esResponse.getAggregations() != null) {
            Terms categoriesAgg = esResponse.getAggregations().get("categories");
            if (categoriesAgg != null) {
                facets.put("categories", categoriesAgg.getBuckets().stream()
                        .map(b -> new FacetEntry(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            Terms brandsAgg = esResponse.getAggregations().get("brands");
            if (brandsAgg != null) {
                facets.put("brands", brandsAgg.getBuckets().stream()
                        .map(b -> new FacetEntry(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            Terms tagsAgg = esResponse.getAggregations().get("tags_agg");
            if (tagsAgg != null) {
                facets.put("tags", tagsAgg.getBuckets().stream()
                        .map(b -> new FacetEntry(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            Histogram priceRangesAgg = esResponse.getAggregations().get("price_ranges");
            if (priceRangesAgg != null) {
                facets.put("priceRanges", priceRangesAgg.getBuckets().stream()
                        .map(b -> new FacetEntry(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }

            Histogram ratingRangesAgg = esResponse.getAggregations().get("rating_ranges");
            if (ratingRangesAgg != null) {
                facets.put("ratingRanges", ratingRangesAgg.getBuckets().stream()
                        .map(b -> new FacetEntry(b.getKeyAsString(), b.getDocCount()))
                        .collect(Collectors.toList()));
            }
        }

        response.setFacets(facets);

        // Log search query asynchronously
        try {
            searchQueryService.logSearchQuery(sanitizedQuery, userId, sessionId,
                    (int) response.getTotalHits(), responseTime, searchRequest);
        } catch (Exception e) {
            logger.warn("Failed to log search query", e);
        }

        return response;
    }

    public List<String> suggest(String prefix) throws IOException {
        if (prefix == null || prefix.isEmpty()) {
            return Collections.emptyList();
        }

        String sanitizedPrefix = InputSanitizer.sanitizeSearchQuery(prefix);
        if (sanitizedPrefix.isEmpty()) {
            return Collections.emptyList();
        }

        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(IndexManagementService.PRODUCTS_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        boolQuery.must(QueryBuilders.matchPhrasePrefixQuery("name.autocomplete", sanitizedPrefix));
        boolQuery.filter(QueryBuilders.termQuery("active", true));

        sourceBuilder.query(boolQuery);
        sourceBuilder.size(10);
        sourceBuilder.fetchSource(new String[]{"name"}, null);

        esRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse esResponse =
                client.search(esRequest, RequestOptions.DEFAULT);

        List<String> suggestions = new ArrayList<>();
        for (SearchHit hit : esResponse.getHits().getHits()) {
            Map<String, Object> source = hit.getSourceAsMap();
            if (source.containsKey("name")) {
                suggestions.add(source.get("name").toString());
            }
        }

        return suggestions.stream().distinct().limit(10).collect(Collectors.toList());
    }

    private void applySorting(SearchSourceBuilder sourceBuilder, String sortBy) {
        if (sortBy == null) sortBy = "relevance";

        switch (sortBy) {
            case "price_asc":
                sourceBuilder.sort(SortBuilders.fieldSort("price").order(SortOrder.ASC));
                break;
            case "price_desc":
                sourceBuilder.sort(SortBuilders.fieldSort("price").order(SortOrder.DESC));
                break;
            case "rating":
                sourceBuilder.sort(SortBuilders.fieldSort("rating").order(SortOrder.DESC));
                sourceBuilder.sort(SortBuilders.fieldSort("reviewCount").order(SortOrder.DESC));
                break;
            case "newest":
                sourceBuilder.sort(SortBuilders.fieldSort("createdAt").order(SortOrder.DESC));
                break;
            case "relevance":
            default:
                sourceBuilder.sort(SortBuilders.scoreSort().order(SortOrder.DESC));
                break;
        }
    }
}

// ==================== Search Query Service ====================

package com.ecommerce.search.service;

import com.ecommerce.search.dto.SearchRequest;
import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.scheduling.annotation.Async;
import org.springframework.scheduling.annotation.EnableAsync;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
@EnableAsync
public class SearchQueryService {

    private static final Logger logger = LoggerFactory.getLogger(SearchQueryService.class);

    @Autowired
    private RestHighLevelClient client;

    private final ObjectMapper objectMapper;

    public SearchQueryService() {
        this.objectMapper = new ObjectMapper();
        this.objectMapper.registerModule(new JavaTimeModule());
    }

    @Async
    public void logSearchQuery(String queryText, String userId, String sessionId,
                                int resultsCount, long responseTimeMs, SearchRequest searchRequest) {
        try {
            SearchQuery searchQuery = new SearchQuery();
            searchQuery.setId(UUID.randomUUID().toString());
            searchQuery.setQueryText(queryText);
            searchQuery.setUserId(userId);
            searchQuery.setSessionId(sessionId);
            searchQuery.setResultsCount(resultsCount);
            searchQuery.setResponseTimeMs(responseTimeMs);
            searchQuery.setSortBy(searchRequest.getSortBy());
            searchQuery.setPage(searchRequest.getPage());
            searchQuery.setPageSize(searchRequest.getPageSize());
            searchQuery.setTimestamp(Instant.now());

            // Build filter summary
            StringBuilder filters = new StringBuilder();
            if (searchRequest.getCategory() != null) filters.append("category:").append(searchRequest.getCategory()).append(";");
            if (searchRequest.getBrand() != null) filters.append("brand:").append(searchRequest.getBrand()).append(";");
            if (searchRequest.getMinPrice() != null) filters.append("minPrice:").append(searchRequest.getMinPrice()).append(";");
            if (searchRequest.getMaxPrice() != null) filters.append("maxPrice:").append(searchRequest.getMaxPrice()).append(";");
            if (searchRequest.getMinRating() != null) filters.append("minRating:").append(searchRequest.getMinRating()).append(";");
            if (searchRequest.getInStock() != null) filters.append("inStock:").append(searchRequest.getInStock()).append(";");
            searchQuery.setFilters(filters.toString());

            String jsonString = objectMapper.writeValueAsString(searchQuery);

            IndexRequest request = new IndexRequest(IndexManagementService.SEARCH_QUERIES_INDEX)
                    .id(searchQuery.getId())
                    .source(jsonString, XContentType.JSON);

            client.index(request, RequestOptions.DEFAULT);
            logger.debug("Search query logged: {}", queryText);
        } catch (Exception e) {
            logger.warn("Failed to log search query: {}", e.getMessage());
        }
    }

    public List<Map<String, Object>> getPopularSearches(int size) throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(IndexManagementService.SEARCH_QUERIES_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);
        sourceBuilder.aggregation(
                AggregationBuilders.terms("popular_queries")
                        .field("queryText.keyword")
                        .size(size)
        );

        esRequest.source(sourceBuilder);

        SearchResponse response = client.search(esRequest, RequestOptions.DEFAULT);

        Terms popularQueries = response.getAggregations().get("popular_queries");
        List<Map<String, Object>> results = new ArrayList<>();

        for (Terms.Bucket bucket : popularQueries.getBuckets()) {
            Map<String, Object> entry = new LinkedHashMap<>();
            entry.put("query", bucket.getKeyAsString());
            entry.put("count", bucket.getDocCount());
            results.add(entry);
        }

        return results;
    }

    public Map<String, Object> getSearchAnalytics() throws IOException {
        org.elasticsearch.action.search.SearchRequest esRequest =
                new org.elasticsearch.action.search.SearchRequest(IndexManagementService.SEARCH_QUERIES_INDEX);

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        sourceBuilder.aggregation(
                AggregationBuilders.terms("zero_results_queries")
                        .field("queryText.keyword")
                        .size(20)
        );

        sourceBuilder.query(QueryBuilders.termQuery("resultsCount", 0));

        esRequest.source(sourceBuilder);

        SearchResponse response = client.search(esRequest, RequestOptions.DEFAULT);

        Map<String, Object> analytics = new LinkedHashMap<>();
        analytics.put("totalSearches", response.getHits().getTotalHits().value);

        Terms zeroResultsQueries = response.getAggregations().get("zero_results_queries");
        List<Map<String, Object>> zeroResults = zeroResultsQueries.getBuckets().stream()
                .map(b -> {
                    Map<String, Object> entry = new LinkedHashMap<>();
                    entry.put("query", b.getKeyAsString());
                    entry.put("count", b.getDocCount());
                    return entry;
                })
                .collect(Collectors.toList());

        analytics.put("zeroResultQueries", zeroResults);

        return analytics;
    }
}

// ==================== Product Controller ====================

package com.ecommerce.search.controller;

import com.ecommerce.search.dto.SearchRequest;
import com.ecommerce.search.dto.SearchResponse;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductService;
import org.elasticsearch.action.bulk.BulkResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.io.IOException;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private static final Logger logger = LoggerFactory.getLogger(ProductController.class);

    @Autowired
    private ProductService productService;

    @PostMapping
    public ResponseEntity<?> indexProduct(@Valid @RequestBody Product product) {
        try {
            Product indexed = productService.indexProduct(product);
            return ResponseEntity.status(HttpStatus.CREATED).body(indexed);
        } catch (IOException e) {
            logger.error("Failed to index product", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(errorResponse("Failed to index product"));
        }
    }

    @PostMapping("/bulk")
    public ResponseEntity<?> bulkIndexProducts(@Valid @RequestBody List<Product> products) {
        if (products == null || products.isEmpty()) {
            return ResponseEntity.badRequest().body(errorResponse("Product list cannot be empty"));
        }
        if (products.size() > 1000) {
            return ResponseEntity.badRequest().body(errorResponse("Bulk index limit is 1000 products"));
        }
        try {
            BulkResponse response = productService.bulkIndexProducts(products);
            Map<String, Object> result = new LinkedHashMap<>();
            result.put("indexed", products.size());
            result.put("hasFailures", response.hasFailures());
            if (response.hasFailures()) {
                result.put("failureMessage", response.buildFailureMessage());
            }
            return ResponseEntity.ok(result);
        } catch (IOException e) {
            logger.error("Failed to bulk index products", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(errorResponse("Failed to bulk index products"));
        }
    }

    @GetMapping("/{id}")
    public ResponseEntity<?> getProduct(@PathVariable String id) {
        try {
            Product product = productService.getProduct(id);
            if (product == null) {
                return ResponseEntity.notFound().build();
            }
            return ResponseEntity.ok(product);
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().body(errorResponse(e.getMessage()));
        } catch (IOException e) {
            logger.error("Failed to get product: {}", id, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(errorResponse("Failed to retrieve product"));
        }
    }

    @PutMapping("/{id}")
    public ResponseEntity<?> updateProduct(@PathVariable String id, @Valid @RequestBody Product product) {
        try {
            Product updated = productService.updateProduct(id, product);
            return ResponseEntity.ok(updated);
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().body(errorResponse(e.getMessage()));
        } catch (IOException e) {
            logger.error("Failed to update product: {}", id, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(errorResponse("Failed to update product"));
        }
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<?> deleteProduct(@PathVariable String id) {
        try {
            boolean deleted = productService.deleteProduct(id);
            if (deleted) {
                return ResponseEntity.ok(Collections.singletonMap("message", "Product deleted successfully"));
            }
            return ResponseEntity.notFound().build();
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().body(errorResponse(e.getMessage()));
        } catch (IOException e) {
            logger.error("Failed to delete product: {}", id, e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(errorResponse("Failed to delete product"));
        }
    }

    @PostMapping("/search")
    public ResponseEntity<?> search(@Valid @RequestBody SearchRequest searchRequest,
                                     Authentication authentication) {
        try {
            String userId = authentication != null ? authentication.getName() : "anonymous";
            SearchResponse response = productService.search(searchRequest, userId, null);
            return ResponseEntity.ok(response);
        } catch (IOException e) {
            logger.error("Search failed", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(errorResponse("Search failed"));
        }
    }

    @GetMapping("/suggest")
    public ResponseEntity<?> suggest(@RequestParam(required = false) String prefix) {
        if (prefix == null || prefix.trim().isEmpty()) {
            return ResponseEntity.ok(Collections.emptyList());
        }
        try {
            List<String> suggestions = productService.suggest(prefix);
            return ResponseEntity.ok(suggestions);
        } catch (IOException e) {
            logger.error("Suggestion failed", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(errorResponse("Suggestion failed"));
        }
    }

    private Map<String, String> errorResponse(String message) {
        Map<String, String> error = new LinkedHashMap<>();
        error.put("error", message);
        return error;
    }
}

// ==================== Admin Controller ====================

package com.ecommerce.search.controller;

import com.ecommerce.search.service.IndexManagementService;
import com.ecommerce.search.service.SearchQueryService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/admin")
public class AdminController {

    private static final Logger logger = LoggerFactory.getLogger(AdminController.class);

    @Autowired
    private SearchQueryService searchQueryService;

    @Autowired
    private IndexManagementService indexManagementService;

    @GetMapping("/popular-searches")
    public ResponseEntity<?> getPopularSearches(
            @RequestParam(defaultValue = "20") int size) {
        if (size < 1 || size > 100) {
            return ResponseEntity.badRequest()
                    .body(Collections.singletonMap("error", "Size must be between 1 and 100"));
        }
        try {
            List<Map<String, Object>> popular = searchQueryService.getPopularSearches(size);
            return ResponseEntity.ok(popular);
        } catch (IOException e) {
            logger.error("Failed to get popular searches", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Collections.singletonMap("error", "Failed to retrieve popular searches"));
        }
    }

    @GetMapping("/search-analytics")
    public ResponseEntity<?> getSearchAnalytics() {
        try {
            Map<String, Object> analytics = searchQueryService.getSearchAnalytics();
            return ResponseEntity.ok(analytics);
        } catch (IOException e) {
            logger.error("Failed to get search analytics", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(Collections.singletonMap("error", "Failed to retrieve search analytics"));
        }
    }

    @GetMapping("/health")
    public ResponseEntity<?> healthCheck() {
        try {
            Map<String, Object> health = new LinkedHashMap<>();
            health.put("status", "UP");
            health.put("productsIndexExists",
                    indexManagementService.indexExists(IndexManagementService.PRODUCTS_INDEX));
            health.put("searchQueriesIndexExists",
                    indexManagementService.indexExists(IndexManagementService.SEARCH_QUERIES_INDEX));
            return ResponseEntity.ok(health);
        } catch (IOException e) {
            logger.error("Health check failed", e);
            Map<String, Object> health = new LinkedHashMap<>();
            health.put("status", "DOWN");
            health.put("error", "Cannot connect to Elasticsearch");
            return ResponseEntity.status(HttpStatus.SERVICE_UNAVAILABLE).body(health);
        }
    }
}

